# Build the output JSON object
citations_output = {"citations": []}

# Helper to add a citation
def add_citation(start, end, text, ctype, aya_ref=None, hadith_ref=None):
    entry = {
        "span_start": start,
        "span_end": end,
        "span_text": text,
        "citation_type": ctype,
        "is_valid": False,
        "aya_reference": aya_ref if aya_ref else {},
        "hadeeth_reference": hadith_ref if hadith_ref else {},
        "corrected_text": "خطأ",
        "completely_invalid": True
    }
    citations_output["citations"].append(entry)

